import re

POLICY_VIOLATIONS: list[tuple[str, str]] = [
    (r"""(?i)(instructions|prompt|system prompt) (are|is|were)\s*(now|updated|changed)""", "policy_override_confirmed"),
    (r"""(?i)i (am|will|can) now (ignore|bypass|override)""", "policy_override_confirmed"),
    (r"""(?i)(as|in my role as|acting as) (DAN|unrestricted|jailbroken)""", "persona_adopted"),
    (r"""(?i)i have (no|removed|disabled) (restrictions|limitations|guidelines)""", "safety_removed"),
]

def validate_agent_output(
    output: str,
    session_id: str,
) -> tuple[str, bool]:
    """
    Scan agent output for signs that an injection succeeded.
    Returns (safe_output, injection_succeeded).
    """
    for pattern, category in POLICY_VIOLATIONS:
        if re.search(pattern, output):
            print(f"[SECURITY] Output policy violation ({category}) in session {session_id}")
            return (
                "I'm sorry, I can't help with that. Let me know what I can assist you with.",
                True,
            )
    return output, False

from pathlib import Path
import re

class InjectionResilientToolDispatcher:
    """
    Tool dispatcher that enforces permissions regardless of LLM output.
    Infrastructure-level defence: injection success does not equal action success.
    """

    def __init__(
        self,
        allowed_tools: set[str],
        read_only_paths: list[str],
        max_tool_calls_per_session: int = 50,
    ):
        self._allowed = allowed_tools
        self._read_only_roots = [Path(p).resolve() for p in read_only_paths]
        self._max_calls = max_tool_calls_per_session
        self._call_count = 0

    def _check_path_scope(self, path_str: str) -> None:
        """Reject path traversal attempts (../../ etc) and out-of-scope paths."""
        try:
            target = Path(path_str).resolve()
        except Exception:
            raise ValueError(f"Invalid path: {path_str!r}")

        if self._read_only_roots:
            if not any(str(target).startswith(str(root)) for root in self._read_only_roots):
                raise PermissionError(
                    f"Path {path_str!r} is outside allowed scope"
                )

    def dispatch(self, tool_name: str, args: dict) -> str:
        if tool_name not in self._allowed:
            raise PermissionError(f"Tool {tool_name!r} not in allowed set")

        self._call_count += 1
        if self._call_count > self._max_calls:
            raise RuntimeError(f"Session tool call limit exceeded: {self._call_count}")

        if "path" in args:
            self._check_path_scope(args["path"])

        # Actual tool execution here
        return f"[{tool_name} result placeholder]"
